// ==========================================
// 2. Helper ProviderIcon Component
// ==========================================

const providerIconMap: Record<string, React.FC<IconProps>> = {
  openai: OpenAIIcon,
  zhipuai: ZhipuAIIcon,
  ollama: OllamaIcon,
  siliconflow: SiliconFlowIcon,
  qwen: QwenIcon,
  google: GoogleGeminiIcon,
  deepseek: DeepSeekIcon,
  anthropic: AnthropicIcon,
  xinference: XinferenceIcon,
};

export const ProviderIcon: React.FC<{ name?: string } & IconProps> = ({ name = '', ...props }) => {
  const normalizedKey = name.toLowerCase().trim();
  const IconComp = providerIconMap[normalizedKey];
  if (!IconComp) {
    // Return a default icon or a fallback badge
    return (
      <span style={{ fontSize: props.size || 24, display: 'inline-flex', alignItems: 'center', justifyContent: 'center' }}>
        🔧
      </span>
    );
  }
  return <IconComp {...props} />;
};

