// ==========================================
// 4. ProviderIconLong and ModelIcon Wrapper Components
// ==========================================

export const ProviderIconLong: React.FC<{ name?: string; size?: number } & React.SVGProps<SVGSVGElement>> = ({
  name = '',
  size = 24,
  ...props
}) => {
  const normalizedKey = name.toLowerCase().trim();
  if (normalizedKey.includes('openai')) return <OpenAIIconLong size={size} {...props} />;
  if (normalizedKey.includes('zhipu') || normalizedKey.includes('chatglm')) return <ZhipuAIIconLong size={size} {...props} />;
  if (normalizedKey.includes('ollama')) return <OllamaIconLong size={size} {...props} />;
  if (normalizedKey.includes('siliconflow')) return <SiliconFlowIconLong size={size} {...props} />;
  if (normalizedKey.includes('qwen')) return <QwenIconLong size={size} {...props} />;
  if (normalizedKey.includes('google') || normalizedKey.includes('gemini')) return <GoogleGeminiIconLong size={size} {...props} />;
  if (normalizedKey.includes('xinference')) return <XinferenceIconLong size={size} {...props} />;
  if (normalizedKey.includes('anthropic') || normalizedKey.includes('anthrapic')) return <AnthropicIconLong size={size} {...props} />;
  if (normalizedKey.includes('deepseek')) return <DeepSeekIconLong size={size} {...props} />;

  // Default fallback to square badge with name
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
      <ProviderIcon name={name} size={size} />
      <span style={{ fontSize: size * 0.6, fontWeight: 700, letterSpacing: 0.5, color: 'var(--flock-text-bright)' }}>
        {name.toUpperCase()}
      </span>
    </div>
  );
};

// Backwards compatibility alias
export const ModelProviderIconLong = ProviderIconLong;

export interface ModelIconProps extends IconProps {
  name: string;
  provider?: string;
}

export const ModelIcon: React.FC<ModelIconProps> = ({ name = '', provider = '', ...props }) => {
  const modelName = name.toLowerCase().trim();
  const providerName = provider.toLowerCase().trim();

  // 1. OpenAI (variants: yellow/orange for o1/o3, green for others)
  if (providerName.includes('openai') || modelName.startsWith('gpt') || modelName.startsWith('o1') || modelName.startsWith('o3')) {
    if (modelName.startsWith('o1') || modelName.startsWith('o3')) {
      return <OpenAIIcon variant="orange" {...props} />;
    }
    return <OpenAIIcon variant="green" {...props} />;
  }

  // 2. Zhipu GLM
  if (providerName.includes('zhipu') || modelName.includes('glm') || modelName.includes('chatglm')) {
    return <ZhipuAIIcon {...props} />;
  }

  // 3. DeepSeek
  if (providerName.includes('deepseek') || modelName.includes('deepseek')) {
    return <DeepSeekIcon {...props} />;
  }

  // 4. Ollama
  if (providerName.includes('ollama') || modelName.includes('ollama')) {
    return <OllamaIcon {...props} />;
  }

  // 5. SiliconFlow
  if (providerName.includes('siliconflow') || modelName.includes('siliconflow')) {
    return <SiliconFlowIcon {...props} />;
  }

  // 6. Qwen
  if (providerName.includes('qwen') || modelName.includes('qwen')) {
    return <QwenIcon {...props} />;
  }

  // 7. Google Gemini
  if (providerName.includes('google') || modelName.includes('gemini')) {
    return <GoogleGeminiIcon {...props} />;
  }


  // 9. Xinference
  if (providerName.includes('xinference') || modelName.includes('xinference')) {
    return <XinferenceIcon {...props} />;
  }

  // Fallback to square ProviderIcon
  return <ProviderIcon name={provider || name} {...props} />;
};

